#include <stdio.h>

int main() {
    FILE *dat;
    double podatak = 1234.0;

    dat = fopen("podatak.dat", "wb");
    if (dat == NULL) {
        printf("Greska pri otvaranju datoteke.\n");
        return 1;
    }

    fwrite(&podatak, sizeof(double), 1, dat);

    fclose(dat);

    printf("Podatak je upisan u binarnu datoteku.\n");

    return 0;
}
